+func transientBeadsDBBackoff(attempt int) time.Duration {
+	if attempt < 1 {
+		attempt = 1
+	}
+	backoff := 50 * time.Millisecond
+	for i := 1; i < attempt; i++ {
+		backoff *= 2
+		if backoff >= 800*time.Millisecond {
+			return 800 * time.Millisecond
+		}
+	}
+	return backoff
+}
