+func stripFlagWithValue(args []string, flag string) []string {
+	if len(args) == 0 {
+		return nil
+	}
+	filtered := make([]string, 0, len(args))
+	for i := 0; i < len(args); i++ {
+		if args[i] != flag {
+			filtered = append(filtered, args[i])
+			continue
+		}
+		if i+1 < len(args) && !strings.HasPrefix(args[i+1], "-") {
+			i++
+		}
+	}
+	return filtered
+}
